import { jsx } from 'react/jsx-runtime';
import { classNames } from '../../helpers/classnames.js';
import { getBEMClasses } from '../../helpers/get-bem.js';
import { PopupsContext } from '../../helpers/popupsContext.js';
import { createContext, useContext, useRef, useState, useLayoutEffect, useEffect } from 'react';
import * as ReactDOM from 'react-dom';
import { Positioner } from './Positioner/Positioner.js';

const createPortalRoot = (rootId, className, onBlur) => {
    const rootElement = document.createElement('div');
    rootElement.id = rootId;
    if (className) {
        rootElement.className = className;
    }
    if (onBlur) {
        rootElement.addEventListener('blur', (event) => onBlur(event)); //TODO: приходит нативное, а не синтетическое событие
        // нужно для корректной работы onBlur, по дефолту div не работает с событиями фокуса
        // TODO: поисследовать рефакторинг этого решения
        rootElement.contentEditable = 'true';
    }
    return rootElement;
};
const MENU_DEFAULT_OFFSET = 8;
const [menuBlock, menuModifier] = getBEMClasses('dsb__dd-menu');
const DropdownContext = createContext({});
/**
 * @deprecated **УСТАРЕВШИЙ КОМПОНЕНТ!** Используйте вместо него компонент NewDropdownMenu из директории /components/NewDropdownMenu.\n\nDropdownMenu - это компонент для отображения выпадающего меню. И используется для постороения других компонентов: Autocomplete, Select и другиe.
 * через некоторое время будет удален
 * */
const DropdownMenu = ({ verticalOffset = MENU_DEFAULT_OFFSET, positionerClassName, horizontalOffset = 0, align = 'center', targetElement, className, applicationRootElementID: applicationRootElementIDProps, dropdownElementID: dropdownElementIDProps, children, onOpen, onBlur, onOutsideClick, scrollable = true, minHeight, dataTestId = 'DropdownMenu', ...rest }) => {
    const { applicationRootElementID: applicationRootElementIDContext, dropdownElementID: dropdownElementIDContext, rootElement: rootElementDDContext, } = useContext(DropdownContext);
    const { applicationElementID, rootElement: rootElementContext } = useContext(PopupsContext);
    const rootElementID = applicationRootElementIDProps || applicationRootElementIDContext || applicationElementID || 'root';
    const dropdownElementID = dropdownElementIDProps || dropdownElementIDContext || 'dsb__dropdown-root';
    const element = rootElementDDContext || rootElementContext;
    const dropdownMenuRef = useRef(null);
    const [rootElement, setRootElement] = useState();
    useLayoutEffect(() => {
        const mountElement = element || document.getElementById(rootElementID);
        if (!mountElement) {
            throw new Error(`Application root element with ID "${rootElementID}" not found`);
        }
        const dropdownElement = createPortalRoot(dropdownElementID, className, onBlur);
        // dropdownElement.setAttribute('data-testid', 'DropdownMenu');
        for (const [key, value] of Object.entries(rest)) {
            dropdownElement.setAttribute(key, value);
        }
        const root = mountElement.appendChild(dropdownElement);
        setRootElement(root);
        return () => {
            dropdownElement.remove();
        };
        // rest намеренно не указан среди зависимостей, т.к приводит к неконтролируемым ререндерам
        // при этом присвоить эти параметры важно, а их изменение при открытом DropdownMenu маловероятно
        // TODO: подумать над переработкой этого блока - все зависимости хука должны быть указаны
    }, [rootElementID, dropdownElementID, className, element]);
    useEffect(() => {
        onOpen?.();
    }, []);
    useEffect(() => {
        const handleOutsideClick = (event) => {
            const targetElement = event?.composedPath()[0];
            const dropdownElement = dropdownMenuRef?.current;
            const isOutsideClick = dropdownElement && !dropdownElement.contains(targetElement);
            if (isOutsideClick) {
                onOutsideClick?.();
            }
        };
        const listenerContainer = rootElement || globalThis;
        listenerContainer?.addEventListener('mousedown', handleOutsideClick);
        return () => listenerContainer?.addEventListener('mousedown', handleOutsideClick);
    }, [onOutsideClick, rootElement]);
    const positionerProps = {
        positionerClassName,
        align,
        horizontalOffset,
        targetElement,
        verticalOffset,
        scrollable,
        minHeight,
    };
    const menuClass = classNames(menuBlock, menuModifier(`align-${align}`));
    return ((rootElement &&
        ReactDOM.createPortal(jsx(Positioner, { ...positionerProps, children: jsx("div", { ref: dropdownMenuRef, className: menuClass, contentEditable: false, "data-testid": dataTestId, children: children }) }), rootElement)) ||
        null);
};

export { DropdownContext, DropdownMenu, createPortalRoot };
